+    #[test]
+    fn violation_display_with_no_pane_or_seq() {
+        let v = ResizeViolation {
+            severity: ResizeViolationSeverity::Warning,
+            kind: ResizeViolationKind::ExcessiveLines,
+            pane_id: None,
+            intent_seq: None,
+            message: "too many lines".to_string(),
